INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-6f0ba476-moex-00464', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-112-34c7f7f6', 'sub-elementary-6f0ba476-02', NULL, 'single_choice', '「我寫小說的理由，追根究柢只有一個。就是讓個人靈魂的尊嚴浮上來，在那裡打上一道光。 為了不讓我們的靈魂被體制套牢、貶低，而經常照亮那裡，鳴響警鐘，那正是故事的任務。 我想藉著寫生與死的故事，寫愛的故事，繼續嘗試讓人哭泣，使人畏怯，引人發笑，每天認 真地繼續創作各種虛構的故事，讓每個靈魂不可替代的珍貴性明確化，這是小說家的工作。」 根據上文，作者對「小說家」的期許是：', '["在作品中，揭示所有靈魂相同而值得讚頌之處", "能凸顯出人性靈魂的尊嚴，並肯定其存在價值", "讓被體制套牢的角色可以鳴響警鐘，早日重生", "藉由虛構的故事使得讀者在哭笑後，洗滌情緒"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:40+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00465', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-112-34c7f7f6', 'sub-elementary-6f0ba476-02', NULL, 'single_choice', '以下是一個兒童繪本愛好者的自述：「繪本既是一個瑰麗的世界，也是一個隱藏著兒童角度 與文學內涵的世界。它不僅在形式特質上無可取代，就連它看世界的『眼神』，也不同於其 他的創作。我因為長年接觸繪本，從中發現了許多屬於兒童的特質，另外也因為它所傳遞出 來的是一些有別於成人世界的價值，而屢屢被書中的小孩顛覆。」 根據上文，下列選項何者最符合對兒童繪本的看法？', '["繪本所具有的形式特質較為瑰麗", "站在兒童的角度發現並了解世界", "以顛覆成人世界的價值觀為起點", "貼近小孩的文學內涵常無可取代"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:40+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00466', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-112-34c7f7f6', 'sub-elementary-6f0ba476-02', NULL, 'single_choice', '「萊爾德專門衝數層樓高的巨浪，每次出海，都像是與死神跳一首腳步繁複的雙人舞。他和 朋友曾經在衝浪時出過嚴重的事故，被巨浪重擊，同伴幾乎喪命在海上。萊爾德用盡力氣把 重傷的同伴拖回岸邊送上救護車後，第一件事竟是拿著浪板掉頭回到海裡，繼續衝浪。事後 有人問他難道不怕嗎？他說：不能害怕。」 根據上文，下列選項敘述正確的是：', '["萊爾德衝浪時，總能以技巧避開危險", "透過衝巨浪，萊爾德提升了衝浪技巧", "萊爾德不費吹灰之力救起溺水的同伴", "萊爾德征服恐懼的方法是直接面對它"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:40+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00467', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-112-34c7f7f6', 'sub-elementary-6f0ba476-02', NULL, 'single_choice', '「你如果順手撿起一塊花崗石的碎片，仔細看它的紋理，會發現含蓄而豐富的色彩，如果加 以放大，不輸一幅抽象畫。每顆石頭都有其獨特的紋理，並不是只有潔白光滑如凝脂的大理 石才是美的。」 下列選項，何者最能呼應上文意旨？', '["萬物自成其紋理，終究會被看見", "經過切磋琢磨，石頭方可展現美", "生活並不缺少美，只是缺少發現", "繁華落盡見真淳，平淡更有滋味"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:40+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00468', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-112-34c7f7f6', 'sub-elementary-6f0ba476-02', NULL, 'single_choice', '「兒子上學和我同路，但他不願搭我的車。即使同車，他戴上耳機——只有一個人能聽的音 樂，是一扇緊閉的門。我只能想像，他的內在世界和我的一樣波濤深邃，但是我進不去。我 慢慢地、慢慢地瞭解到，所謂父女母子一場，只不過意味著，你和他的緣分就是今生今世不 斷地在目送他的背影漸行漸遠。你站立在小路的這一端，看著他逐漸消失在小路轉彎的地 方，而且，『他用背影默默告訴你：不必追』。」 根據上文，作者最主要想表達的是：', '["人世間所謂親情無非陪他一段，難以相伴一生", "父母與子女往往存在隔閡，很難有真正的溝通", "處於叛逆期的兒子彷彿絕緣體，令人難以理解", "子女往往冷漠地回應父母，讓父母難過與失望"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:40+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00469', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-112-34c7f7f6', 'sub-elementary-6f0ba476-02', NULL, 'single_choice', '承上題，文末「他用背影默默告訴你：不必追」，最適合的解釋是：', '["父母停留在自己的世界，很難追上子女前進的步伐", "子女自有自己的世界，父母該適時放手，不必執著", "子女終將脫離父母掌控，彼此情感亦難免日漸稀薄", "父母應妥善安排自己的晚年，養兒防老並不切實際"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:40+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00470', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-112-34c7f7f6', 'sub-elementary-6f0ba476-02', NULL, 'single_choice', '「在荷蘭的發展歷程，地理、人口等都與臺灣的永續發展議題相似。全球氣候變遷與荷蘭人 口增長同時來襲，國土容易淹水，缺乏宜居土地的荷蘭，需要一個重新思考土地利用的方法。 在此背景下，不能避免淹水，那就和水共存的想法，促成漂浮屋的出現。2015 年，荷蘭想 出了鹿特丹水廣場的想法，就設計一個沒有洪水的時候是遊憩的設施，洪水來了就讓它成為 淹水的環境，而減少因為都市建築造成的洪水問題，同時增加與自然共存的環境。」 根據上文，下列選項何者最符合文意？', '["水能載舟，亦能覆舟", "因勢利導，順勢而為", "謀事在人，成事在天", "江河行地，與時俱進"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:40+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00471', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-112-34c7f7f6', 'sub-elementary-6f0ba476-02', NULL, 'single_choice', '「宗教有時會被看成是一種『迷信』，但透過這樣實地走訪臺灣各地廟宇的研究，讓我們對 宗教有了不同的理解：無論是化解悲情的受難儀式、明辨是非的神判儀式，或是重啟調解機 制的告陰狀，表面上是宗教活動，其實都是在處理人們的心理問題或社會問題。」 根據上文，下列選項最符合文意的是：', '["宗教活動幫助民眾面對自己的內心", "宗教具有洞悉社會問題的神秘力量", "宗教的功能多是信眾的期待與想像", "不該以迷信看待宗教的超自然特性"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:40+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00472', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-112-34c7f7f6', 'sub-elementary-6f0ba476-02', NULL, 'single_choice', '〔記者新北報導〕板橋某國中校舍改建與地下停車場工程挖出長10多公尺、胸徑3公尺的 楠木類古木，判定樹齡約300多年（在地底約5千年），校方決議取部分結合公共藝術，其 餘不予保存，引發爭議。某大學地質科學系教授說：「古木價值在於歷經的歲月及意義，以 稀有性、教育性及觀賞性來看都值得完整保留。」 根據上文，下列選項何者正確？', '["校方的決議是針對教育的需求", "學者主張保留古木以見證歷史", "學者建議取稀有木段凸顯觀賞價值", "校方為推動公共藝術保存完整古木"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:40+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00473', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-112-34c7f7f6', 'sub-elementary-6f0ba476-02', NULL, 'single_choice', '「目前，AI 和機器人還不太可能完全取代整個產業。如果是需要同時運用廣泛技能組合的 工作，又或是需要應付難以預見的情境，比較難用機器來取代。由此看來，醫師的主要工作 在於處理資訊：吸收醫療資訊、分析資料、再提出診斷。相對之下，護理師需要有良好的運 動能力和情緒智力，才能幫病人打針、換繃帶，或是壓制住激動的病人。因此，出現智慧型 手機 AI 醫師的時間，很有可能會遠遠早於可靠的護理機器人。」 根據上文，下列選項何者最符合文意？', '["AI和機器人的發展受限，前景不被看好", "對機器人來說，看病診斷比換繃帶更難", "護理師需要比醫師具備更多的專業知識", "醫師在未來比護理師更有可能被AI取代"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:40+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL)
